/* ============================================================
   SYSTEL - SONS EMBARQUÉS (base64 WAV)
   Élimine les erreurs 404 sur les fichiers MP3 externes
   ============================================================ */
const SOUND_BIP = 'data:audio/wav;base64,';
const SOUND_ACQ = 'data:audio/wav;base64,';

function playBip(loop) {
  try {
    window._bipAudio = new Audio(SOUND_BIP);
    window._bipAudio.loop = !!loop;
    window._bipAudio.volume = 0.9;
    window._bipAudio.play().catch(()=>{});
  } catch(e) {}
}
function stopBip() {
  if (window._bipAudio) { window._bipAudio.pause(); window._bipAudio.currentTime = 0; window._bipAudio = null; }
}
function playAck() {
  stopBip();
  try {
    const a = new Audio(SOUND_ACQ);
    a.volume = 0.9;
    a.play().catch(()=>{});
  } catch(e) {}
}
